   602→	private getBroadCategoryNames({
   603→		categories,
   604→		allCategories,
   605→	}: {
   606→		styleId?: number;
   607→		categories: MMSStyleToProcess['categories'];
   608→		allCategories: MMSAllStyleCategory[];
   609→	}): string[] {
   610→		const activeCategories = categories
   611→			.map((cat) => {
   612→				const fullCategory = allCategories.find((c) => c._id === cat.parent_id);
   613→				if (fullCategory) {
   614→					cat['parent'] = fullCategory;
   615→				}
   616→				return cat;
   617→			})
   618→			.filter((cat) => cat.active);
   619→
   620→		const allParents = activeCategories
   621→			.map((category) => category['parent'] ?? { ...category, _id: category.id })
   622→			.filter(Boolean) as MMSAllStyleCategory[];
   623→
   624→		const uniqueParents = allParents.reduce<MMSAllStyleCategory[]>((acc, parent) => {
   625→			if (TAXONOMY_CAT_IDS.includes(parent._id)) {
   626→				return acc;
   627→			}
   628→
   629→			if (!acc.some((p) => p._id === parent._id)) {
   630→				acc.push(parent);
   631→			}
   632→
   633→			return acc;
   634→		}, []);
   635→
   636→		const names = uniqueParents
   637→			.map((parent) => parent['name'])
   638→			.filter((name) => name && !EXCLUDED_CAT_NAMES.includes(name as string)) as string[];
   639→
   640→		return [...new Set(names)];
   641→	}
