   669→	private calculateLink({
   670→		style,
   671→		allCategories,
   672→	}: {
   673→		style: MMSStyleToProcess;
   674→		allCategories: MMSAllStyleCategory[];
   675→	}): Breadcrumb | null {
   676→		function urlFriendly(str: string): string {
   677→			return str
   678→				.toLowerCase()
   679→				.replace(/&reg;/g, '®')
   680→				.replace(/\//g, '-')
   681→				.replace(/\s+/g, '-')
   682→				.replace(/[^\+\-0-9_a-z]/g, '')
   683→				.replace(/^-+|-+$/g, '')
   684→				.replace(/-+/g, '-');
   685→		}
   686→
   687→		const primaryCategory = style.primary_category;
   688→
   689→		if (!primaryCategory) {
   690→			return null;
   691→		}
   692→
   693→		const primaryCatParent = allCategories.find(
   694→			(cat) => cat._id === primaryCategory.parent_id,
   695→		);
   696→
   697→		const primaryCatParentName = primaryCatParent?.['name'] as string;
   698→		const categoryName = primaryCategory.name;
   699→
   700→		const firstPartLink = !primaryCatParent
   701→			? '/products'
   702→			: `/products/${urlFriendly(primaryCatParentName)}`;
   703→
   704→		const path = `${firstPartLink}/${urlFriendly(categoryName)}/${urlFriendly(style.name)}/${style.id}`;
   705→
   706→		return {
   707→			name: style.name,
   708→			path: path,
   709→		};
   710→	}
