   717→	private extractCategoriesWithParents({
   718→		categoryIds,
   719→		allCategories,
   720→	}: {
   721→		categoryIds: number[];
   722→		allCategories: MMSAllStyleCategory[];
   723→	}): number[] {
   724→		const allCategoryIds = new Set<number>();
   725→
   726→		for (const categoryId of categoryIds) {
   727→			allCategoryIds.add(categoryId);
   728→
   729→			const parentIds = this.getAllParentCategoryIds({ categoryId, allCategories });
   730→			for (const parentId of parentIds) {
   731→				allCategoryIds.add(parentId);
   732→			}
   733→		}
   734→
   735→		return Array.from(allCategoryIds).sort((a, b) => a - b);
   736→	}
   737→
   738→	private getAllParentCategoryIds({
   739→		categoryId,
   740→		allCategories,
   741→	}: {
   742→		categoryId: number;
   743→		allCategories: MMSAllStyleCategory[];
   744→	}): number[] {
   745→		const parents: number[] = [];
   746→		const category = allCategories.find((cat) => cat._id === categoryId);
   747→
   748→		if (!category?.['parent_id']) {
   749→			return parents;
   750→		}
   751→
   752→		let currentParentId = category['parent_id'] as number;
   753→
   754→		while (currentParentId) {
   755→			parents.push(currentParentId);
   756→
   757→			const parentCategory = allCategories.find((cat) => cat._id === currentParentId);
   758→			if (!parentCategory?.['parent_id']) {
   759→				break;
   760→			}
   761→
   762→			currentParentId = parentCategory['parent_id'] as number;
   763→		}
   764→
   765→		return parents;
   766→	}
