   768→	private getRootCategoryId({
   769→		style,
   770→		allCategories,
   771→	}: {
   772→		style: MMSStyleToProcess;
   773→		allCategories: MMSAllStyleCategory[];
   774→	}): number | null {
   775→		if (!style.primary_category) {
   776→			return null;
   777→		}
   778→
   779→		const primaryCategory = allCategories.find(
   780→			(cat) => cat._id === style.primary_category_id,
   781→		);
   782→		if (!primaryCategory) {
   783→			return null;
   784→		}
   785→
   786→		let currentCategory = primaryCategory;
   787→		while (currentCategory['parent_id']) {
   788→			const parentCategory = allCategories.find(
   789→				(cat) => cat._id === currentCategory['parent_id'],
   790→			);
   791→			if (!parentCategory) break;
   792→			currentCategory = parentCategory;
   793→		}
   794→
   795→		return !currentCategory['parent_id'] ? currentCategory._id : null;
   796→	}
   797→}
